7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This is a very basic synchronous FIFO. It  has optional level- and
11	-- almost-full/empty ports.
12	--
13	-- Documentation:
14	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_fifo_sync.md
15	--
16	-- Note: The link points to the documentation of the latest release. If you
17	--       use an older version, the documentation might not match the code.
18	
19	---------------------------------------------------------------------------------------------------
20	-- Libraries
21	---------------------------------------------------------------------------------------------------
22	library ieee;
23	    use ieee.std_logic_1164.all;
24	    use ieee.numeric_std.all;
25	
26	library work;
27	    use work.olo_base_pkg_math.all;
28	
29	---------------------------------------------------------------------------------------------------
30	-- Entity
31	---------------------------------------------------------------------------------------------------
32	entity olo_base_fifo_sync is
33	    generic (
34	        Width_g         : positive;
35	        Depth_g         : positive;
36	        AlmFullOn_g     : boolean   := false;
37	        AlmFullLevel_g  : natural   := 0;
38	        AlmEmptyOn_g    : boolean   := false;
39	        AlmEmptyLevel_g : natural   := 0;
40	        RamStyle_g      : string    := "auto";
41	        RamBehavior_g   : string    := "RBW";
42	        ReadyRstState_g : std_logic := '1'
43	    );
44	    port (
45	        -- Control Ports
46	        Clk           : in    std_logic;
47	        Rst           : in    std_logic;
48	        -- Input Data
49	        In_Data       : in    std_logic_vector(Width_g - 1 downto 0);
50	        In_Valid      : in    std_logic := '1';
51	        In_Ready      : out   std_logic;
52	        In_Level      : out   std_logic_vector(log2ceil(Depth_g + 1) - 1 downto 0);
53	        -- Output Data
54	        Out_Data      : out   std_logic_vector(Width_g - 1 downto 0);
55	        Out_Valid     : out   std_logic;
56	        Out_Ready     : in    std_logic := '1';
57	        Out_Level     : out   std_logic_vector(log2ceil(Depth_g + 1) - 1 downto 0);
58	        -- Status
59	        Full          : out   std_logic;
60	        AlmFull       : out   std_logic;
61	        Empty         : out   std_logic;
62	        AlmEmpty      : out   std_logic
63	    );
64	end entity;
65	
66	---------------------------------------------------------------------------------------------------
67	-- Architecture
68	---------------------------------------------------------------------------------------------------
69	architecture rtl of olo_base_fifo_sync is
70	
71	    type TwoProcess_r is record
72	        WrLevel : std_logic_vector(In_Level'range);
73	        RdLevel : std_logic_vector(Out_Level'range);
74	        RdUp    : std_logic;
75	        WrDown  : std_logic;
76	        WrAddr  : std_logic_vector(log2ceil(Depth_g) - 1 downto 0);
77	        RdAddr  : std_logic_vector(log2ceil(Depth_g) - 1 downto 0);
78	    end record;
79	
80	    signal r, r_next : TwoProcess_r;
81	
82	    signal RamWr     : std_logic;
83	    signal RamRdAddr : std_logic_vector(log2ceil(Depth_g) - 1 downto 0);
84	
85	begin
86	
87	    p_comb : process (all) is
88	        variable v : TwoProcess_r;
89	    begin
90	        -- hold variables stable
91	        v := r;
92	
93	        -- Write side
94	        v.RdUp := '0';
95	        RamWr  <= '0';
96	        if unsigned(r.WrLevel) /= Depth_g and In_Valid = '1' then
97	            if unsigned(r.WrAddr) /= Depth_g - 1 then
98	                v.WrAddr := std_logic_vector(unsigned(r.WrAddr) + 1);
99	            else
100	                v.WrAddr := (others => '0');
101	            end if;
102	            RamWr  <= '1';
103	            v.RdUp := '1';
104	            if r.WrDown = '0' then
105	                v.WrLevel := std_logic_vector(unsigned(r.WrLevel) + 1);
106	            end if;
107	        elsif r.WrDown = '1' then
108	            v.WrLevel := std_logic_vector(unsigned(r.WrLevel) - 1);
109	        end if;
110	
111	        -- Write side status
112	        if unsigned(r.WrLevel) = Depth_g then
113	            In_Ready <= '0';
114	            Full     <= '1';
115	        else
116	            In_Ready <= '1';
117	            Full     <= '0';
118	        end if;
119	        -- Artificially keep InRdy low during reset if required
120	        if (ReadyRstState_g = '0') and (Rst = '1') then
121	            In_Ready <= '0';
122	        end if;
123	
124	        if AlmFullOn_g and unsigned(r.WrLevel) >= AlmFullLevel_g then
125	            AlmFull <= '1';
126	        else
127	            AlmFull <= '0';
128	        end if;
129	
130	        -- Read side
131	        v.WrDown := '0';
132	        if unsigned(r.RdLevel) /= 0 and Out_Ready = '1' then
133	            if unsigned(r.RdAddr) /= Depth_g - 1 then
134	                v.RdAddr := std_logic_vector(unsigned(r.RdAddr) + 1);
135	            else
136	                v.RdAddr := (others => '0');
137	            end if;
138	            v.WrDown := '1';
139	            if r.RdUp = '0' then
140	                v.RdLevel := std_logic_vector(unsigned(r.RdLevel) - 1);
141	            end if;
142	        elsif r.RdUp = '1' then
143	            v.RdLevel := std_logic_vector(unsigned(r.RdLevel) + 1);
144	        end if;
145	        RamRdAddr <= v.RdAddr;
146	
147	        -- Read side status
148	        if unsigned(r.RdLevel) > 0 then
149	            Out_Valid <= '1';
150	            Empty     <= '0';
151	        else
152	            Out_Valid <= '0';
153	            Empty     <= '1';
154	        end if;
155	
156	        if AlmEmptyOn_g and unsigned(r.RdLevel) <= AlmEmptyLevel_g then
157	            AlmEmpty <= '1';
158	        else
159	            AlmEmpty <= '0';
160	        end if;
161	
162	        -- Assign signal
163	        r_next <= v;
164	
165	    end process;
166	
167	    -- Synchronous Outputs
168	    Out_Level <= r.RdLevel;
169	    In_Level  <= r.WrLevel;
170	
171	    p_seq : process (Clk) is
172	    begin
173	        if rising_edge(Clk) then
174	            r <= r_next;
175	            if Rst = '1' then
176	                r.WrLevel <= (others => '0');
177	                r.RdLevel <= (others => '0');
178	                r.RdUp    <= '0';
179	                r.WrDown  <= '0';
180	                r.WrAddr  <= (others => '0');
181	                r.RdAddr  <= (others => '0');
182	            end if;
183	        end if;
184	    end process;
185	
186	    i_ram : entity work.olo_base_ram_sdp
187	        generic map (
188	            Depth_g         => Depth_g,
189	            Width_g         => Width_g,
190	            RamStyle_g      => RamStyle_g,
191	            RamBehavior_g   => RamBehavior_g
192	        )
193	        port map (
194	            Clk         => Clk,
195	            Wr_Addr     => r.WrAddr,
196	            Wr_Ena      => RamWr,
197	            Wr_Data     => In_Data,
198	            Rd_Addr     => RamRdAddr,
199	            Rd_Data     => Out_Data
200	        );
201	
202	end architecture;
