1	---------------------------------------------------------------------------------------------------
2	-- Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
3	-- Copyright (c) 2024 by Oliver Bruendler, Switzerland
4	-- Authors: Oliver Bruendler
5	---------------------------------------------------------------------------------------------------
6	
7	---------------------------------------------------------------------------------------------------
8	-- Libraries
9	---------------------------------------------------------------------------------------------------
10	library ieee;
11	    use ieee.std_logic_1164.all;
12	    use ieee.numeric_std.all;
13	    use ieee.math_real.all;
14	
15	library vunit_lib;
16	    context vunit_lib.vunit_context;
17	
18	library olo;
19	    use olo.olo_base_pkg_math.all;
20	    use olo.olo_base_pkg_logic.all;
21	
22	---------------------------------------------------------------------------------------------------
23	-- Entity
24	---------------------------------------------------------------------------------------------------
25	-- vunit: run_all_in_same_sim
26	entity olo_base_fifo_sync_tb is
27	    generic (
28	        runner_cfg      : string;
29	        AlmFullOn_g     : boolean              := true;
30	        AlmEmptyOn_g    : boolean              := true;
31	        Depth_g         : natural              := 32;
32	        RamBehavior_g   : string               := "RBW";
33	        ReadyRstState_g : integer range 0 to 1 := 1
34	    );
35	end entity;
36	
37	architecture sim of olo_base_fifo_sync_tb is
38	
39	    -----------------------------------------------------------------------------------------------
40	    -- Constants
41	    -----------------------------------------------------------------------------------------------
42	    constant DataWidth_c     : integer := 16;
43	    constant AlmFullLevel_c  : natural := Depth_g - 3;
44	    constant AlmEmptyLevel_c : natural := 5;
45	
46	    -----------------------------------------------------------------------------------------------
47	    -- TB Defnitions
48	    -----------------------------------------------------------------------------------------------
49	    constant ClockFrequency_c : real := 100.0e6;
50	    constant ClockPeriod_c    : time := (1 sec) / ClockFrequency_c;
51	
52	    -----------------------------------------------------------------------------------------------
53	    -- Interface Signals
54	    -----------------------------------------------------------------------------------------------
55	    signal Clk       : std_logic                                            := '0';
56	    signal Rst       : std_logic                                            := '1';
57	    signal In_Data   : std_logic_vector(DataWidth_c - 1 downto 0)           := (others => '0');
58	    signal In_Valid  : std_logic                                            := '0';
59	    signal In_Ready  : std_logic                                            := '0';
60	    signal Out_Data  : std_logic_vector(DataWidth_c - 1 downto 0)           := (others => '0');
61	    signal Out_Valid : std_logic                                            := '0';
62	    signal Out_Ready : std_logic                                            := '0';
63	    signal Full      : std_logic                                            := '0';
64	    signal Empty     : std_logic                                            := '0';
65	    signal AlmFull   : std_logic                                            := '0';
66	    signal AlmEmpty  : std_logic                                            := '0';
67	    signal In_Level  : std_logic_vector(log2ceil(Depth_g + 1) - 1 downto 0) := (others => '0');
68	    signal Out_Level : std_logic_vector(log2ceil(Depth_g + 1) - 1 downto 0) := (others => '0');
69	
70	begin
71	
72	    -----------------------------------------------------------------------------------------------
73	    -- DUT
74	    -----------------------------------------------------------------------------------------------
75	    i_dut : entity olo.olo_base_fifo_sync
76	        generic map (
77	            Width_g             => DataWidth_c,
78	            Depth_g             => Depth_g,
79	            AlmFullOn_g         => AlmFullOn_g,
80	            AlmFullLevel_g      => AlmFullLevel_c,
81	            AlmEmptyOn_g        => AlmEmptyOn_g,
82	            AlmEmptyLevel_g     => AlmEmptyLevel_c,
83	            RamBehavior_g       => RamBehavior_g,
84	            ReadyRstState_g     => toStdl(ReadyRstState_g)
85	        )
86	        port map (
87	            Clk       => Clk,
88	            Rst       => Rst,
89	            In_Data   => In_Data,
90	            In_Valid  => In_Valid,
91	            In_Ready  => In_Ready,
92	            Out_Data  => Out_Data,
93	            Out_Valid => Out_Valid,
94	            Out_Ready => Out_Ready,
95	            Full      => Full,
96	            Empty     => Empty,
97	            AlmFull   => AlmFull,
98	            AlmEmpty  => AlmEmpty,
99	            In_Level  => In_Level,
100	            Out_Level => Out_Level
101	        );
102	
103	    -----------------------------------------------------------------------------------------------
104	    -- Clock
105	    -----------------------------------------------------------------------------------------------
106	    Clk <= not Clk after 0.5 * ClockPeriod_c;
107	
108	    -----------------------------------------------------------------------------------------------
109	    -- TB Control
110	    -----------------------------------------------------------------------------------------------
111	    test_runner_watchdog(runner, 10 ms);
112	
113	    p_control : process is
114	    begin
115	        test_runner_setup(runner, runner_cfg);
116	
117	        while test_suite loop
118	
119	            -- *** Reset ***
120	            -- Reset
121	            wait until rising_edge(Clk);
122	            Rst <= '1';
123	            wait until rising_edge(Clk);
124	            -- check if ready state during reset is correct
125	            check_equal(toStdl(ReadyRstState_g), In_Ready, "In_Ready reset state not according to generic");
126	            wait for 1 us;
127	
128	            -- Remove reset
129	            wait until rising_edge(Clk);
130	            Rst <= '0';
131	            wait until rising_edge(Clk);
132	
133	            if run("Reset") then
134	                -- Check Reset State
135	                check_equal(In_Ready, '1', "In_Ready after reset state not '1'");
136	                check_equal(Out_Valid, '0', "Out_Valid reset state not '0'");
137	                check_equal(Full, '0', "Full reset state not '0'");
138	                check_equal(Empty, '1', "Empty reset state not '1'");
139	                check_equal(In_Level, 0, "In_Level reset state not 0");
140	                check_equal(Out_Level, 0, "In_Level reset state not 0");
141	                if AlmFullOn_g then
142	                    check_equal(AlmFull, '0', "AlmFull reset state not '0'");
143	                end if;
144	                if AlmEmptyOn_g then
145	                    check_equal(AlmEmpty, '1',  "AlmEmpty reset state not '1'");
146	                end if;
147	
148	            elsif run("TwoWordsWriteAndRead") then
149	
150	                -- Write 1
151	                wait until falling_edge(Clk);
152	                In_Data  <= x"0001";
153	                In_Valid <= '1';
154	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
155	                check_equal(Out_Valid, '0', "Out_Valid wnt high unexpectedly");
156	                check_equal(Empty, '1', "Empty not high");
157	                check_equal(In_Level, 0, "In_Level not 0");
158	                check_equal(Out_Level, 0, "Out_Level not 0");
159	
160	                -- Write 2
161	                wait until falling_edge(Clk);
162	                In_Data <= x"0002";
163	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
164	                check_equal(Out_Valid, '0', "Out_Valid wnt high unexpectedly");
165	                check_equal(Empty, '1', "Empty not high");
166	                check_equal(In_Level, 1, "In_Level not 0");
167	                check_equal(Out_Level, 0, "Out_Level not 0");
168	
169	                -- Pause 1
170	                wait until falling_edge(Clk);
171	                In_Data  <= x"0003";
172	                In_Valid <= '0';
173	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
174	                check_equal(Out_Valid, '1', "Out_Valid not high");
175	                check_equal(Out_Data, 16#0001#, "Illegal Out_Data 1");
176	                check_equal(Empty, '0', "Empty not low");
177	                check_equal(In_Level, 2, "In_Level not 2");
178	                check_equal(Out_Level, 1, "Out_Level not 1");
179	
180	                -- Pause 2
181	                wait until falling_edge(Clk);
182	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
183	                check_equal(Out_Valid, '1', "Out_Valid not high");
184	                check_equal(Out_Data, 16#0001#, "Illegal Out_Data 1");
185	                check_equal(Empty, '0', "Empty not low");
186	                check_equal(In_Level, 2, "In_Level not 2");
187	                check_equal(Out_Level, 2, "Out_Level not 2");
188	
189	                -- Read ack 1
190	                wait until falling_edge(Clk);
191	                Out_Ready <= '1';
192	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
193	                check_equal(Out_Valid, '1', "Out_Valid not high");
194	                check_equal(Out_Data, 16#0001#, "Illegal Out_Data 1");
195	                check_equal(Empty, '0', "Empty not low");
196	                check_equal(In_Level, 2, "In_Level not 2");
197	                check_equal(Out_Level, 2, "Out_Level not 2");
198	
199	                -- Read ack 2
200	                wait until falling_edge(Clk);
201	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
202	                check_equal(Out_Valid, '1', "Out_Valid not high");
203	                check_equal(Out_Data, 16#0002#, "Illegal Out_Data 2");
204	                check_equal(Empty, '0', "Empty not low");
205	                check_equal(In_Level, 2, "In_Level not 2");
206	                check_equal(Out_Level, 1, "Out_Level not 1");
207	
208	                -- empty 1
209	                wait until falling_edge(Clk);
210	                Out_Ready <= '0';
211	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
212	                check_equal(Out_Valid, '0', "Out_Valid not high");
213	                check_equal(Empty, '1', "Empty not high");
214	                check_equal(In_Level, 1, "In_Level not 1");
215	                check_equal(Out_Level, 0, "Out_Level not 0");
216	
217	                -- empty 2
218	                wait until falling_edge(Clk);
219	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
220	                check_equal(Out_Valid, '0', "Out_Valid not high");
221	                check_equal(Empty, '1', "Empty not high");
222	                check_equal(In_Level, 0, "In_Level not 0");
223	                check_equal(Out_Level, 0, "Out_Level not 0");
224	
225	            elsif run("WriteFullFifo") then
226	                wait until falling_edge(Clk);
227	
228	                -- Fill FIFO
229	                for i in 0 to Depth_g - 1 loop
230	                    In_Valid <= '1';
231	                    In_Data  <= toUslv(i, In_Data'length);
232	                    wait until falling_edge(Clk);
233	                end loop;
234	
235	                In_Valid <= '0';
236	                wait until falling_edge(Clk);
237	                wait until falling_edge(Clk);
238	                check_equal(Full, '1', "Full not asserted");
239	                check_equal(In_Level, Depth_g, "In_Level not Full");
240	                check_equal(Out_Level, Depth_g, "Out_Level not Full");
241	
242	                -- Add more data (not written because full)
243	                In_Valid <= '1';
244	                In_Data  <= x"ABCD";
245	                wait until falling_edge(Clk);
246	                In_Data  <= x"8765";
247	                wait until falling_edge(Clk);
248	                In_Valid <= '0';
249	                wait until falling_edge(Clk);
250	                wait until falling_edge(Clk);
251	                check_equal(Full, '1', "Full not asserted");
252	                check_equal(In_Level, Depth_g, "In_Level not Full");
253	                check_equal(Out_Level, Depth_g, "Out_Level not Full");
254	
255	                -- Check read
256	                for i in 0 to Depth_g - 1 loop
257	                    Out_Ready <= '1';
258	                    check_equal(Out_Data, i, "Read wrong data in word " & integer'image(i));
259	                    wait until falling_edge(Clk);
260	                end loop;
261	
262	                Out_Ready <= '0';
263	                wait until falling_edge(Clk);
264	                wait until falling_edge(Clk);
265	                check_equal(Empty, '1', "Empty not asserted");
266	                check_equal(Full, '0', "Full not de-asserted");
267	                check_equal(In_Level, 0, "In_Level not Empty");
268	                check_equal(Out_Level, 0, "Out_Level not Empty");
269	
270	            elsif run("ReadEmptyFifo") then
271	                wait until falling_edge(Clk);
272	                check_equal(Empty, '1', "Empty not asserted");
273	
274	                -- read
275	                wait until falling_edge(Clk);
276	                Out_Ready <= '1';
277	                wait until falling_edge(Clk);
278	                Out_Ready <= '0';
279	
280	                -- check correct output
281	                wait until falling_edge(Clk);
282	                wait until falling_edge(Clk);
283	                check_equal(Empty, '1', "Empty not asserted");
284	                check_equal(In_Level, 0, "In_Level not Empty");
285	                check_equal(Out_Level, 0, "Out_Level not Empty");
286	                In_Valid  <= '1';
287	                In_Data   <= x"8765";
288	                wait until falling_edge(Clk);
289	                In_Valid  <= '0';
290	                wait until falling_edge(Clk);
291	                wait until falling_edge(Clk);
292	                check_equal(Empty, '0', "Empty not de-asserted");
293	                check_equal(In_Level, 1, "In_Level not 1");
294	                check_equal(Out_Level, 1, "Out_Level not 1");
295	                check_equal(Out_Data, 16#8765#, "Read wrong data");
296	                Out_Ready <= '1';
297	                wait until falling_edge(Clk);
298	                Out_Ready <= '0';
299	                wait until falling_edge(Clk);
300	                wait until falling_edge(Clk);
301	                check_equal(Empty, '1', "Empty not asserted");
302	                check_equal(In_Level, 0, "In_Level not Empty");
303	                check_equal(Out_Level, 0, "Out_Level not Empty");
304	
305	            elsif run("AlmostFlags") then
306	                wait until falling_edge(Clk);
307	
308	                -- fill FIFO
309	                for i in 0 to Depth_g - 1 loop
310	                    In_Valid <= '1';
311	                    In_Data  <= std_logic_vector(to_unsigned(i, In_Data'length));
312	                    wait until falling_edge(Clk);
313	                    In_Valid <= '0';
314	                    wait until falling_edge(Clk);
315	                    wait until falling_edge(Clk);
316	                    check_equal(In_Level, i+1, "In_Level wrong fill");
317	                    check_equal(Out_Level, i+1, "Out_Level wrong fill");
318	                    if AlmFullOn_g then
319	                        if i + 1 >= AlmFullLevel_c then
320	                            check_equal(AlmFull, '1', "Full not set");
321	                        else
322	                            check_equal(AlmFull, '0', "Almost Full set");
323	                        end if;
324	                    end if;
325	                    if AlmEmptyOn_g then
326	                        if i + 1 <= AlmEmptyLevel_c then
327	                            check_equal(AlmEmpty, '1', "Almost Empty not set");
328	                        else
329	                            check_equal(AlmEmpty, '0', "Almost Empty set");
330	                        end if;
331	                    end if;
332	                end loop;
333	
334	                -- flush
335	                for i in Depth_g - 1 downto 0 loop
336	                    Out_Ready <= '1';
337	                    wait until falling_edge(Clk);
338	                    Out_Ready <= '0';
339	                    wait until falling_edge(Clk);
340	                    wait until falling_edge(Clk);
341	                    check_equal(In_Level, i, "In_Level wrong flush");
342	                    check_equal(Out_Level, i, "Out_Level wrong flush");
343	                    if AlmFullOn_g then
344	                        if i >= AlmFullLevel_c then
345	                            check_equal(AlmFull, '1', "Almost Full not set");
346	                        else
347	                            check_equal(AlmFull, '0', "Almost Full set");
348	                        end if;
349	                    end if;
350	                    if AlmEmptyOn_g then
351	                        if i <= AlmEmptyLevel_c then
352	                            check_equal(AlmEmpty, '1', "Almost Empty not set");
353	                        else
354	                            check_equal(AlmEmpty, '0', "Almost Empty set");
355	                        end if;
356	                    end if;
357	                end loop;
358	
359	            elsif run("DiffDutyCycle") then
360	                wait until falling_edge(Clk);
361	
362	                -- Loop through write duty cycles
363	                for wrDel in 0 to 4 loop
364	
365	                    -- Loop through read duty cycles
366	                    for rdDel in 0 to 4 loop
367	                        check_equal(Empty, '1', "Empty not asserted");
368	
369	                        -- Write data
370	                        for i in 0 to 4 loop
371	                            In_Valid <= '1';
372	                            In_Data  <= toUslv(i, In_Data'length);
373	                            wait until falling_edge(Clk);
374	
375	                            -- Wrie delay
376	                            for k in 1 to wrDel loop
377	                                In_Valid <= '0';
378	                                In_Data  <= x"0000";
379	                                wait until falling_edge(Clk);
380	                            end loop;
381	
382	                        end loop;
383	
384	                        In_Valid <= '0';
385	
386	                        -- Read data
387	                        for i in 0 to 4 loop
388	                            Out_Ready <= '1';
389	                            check_equal(Out_Data, i, "Wrong data");
390	                            wait until falling_edge(Clk);
391	
392	                            -- Read delay
393	                            for k in 1 to rdDel loop
394	                                Out_Ready <= '0';
395	                                wait until falling_edge(Clk);
396	                            end loop;
397	
398	                        end loop;
399	
400	                        Out_Ready <= '0';
401	                        check_equal(Empty, '1', "Empty not asserted");
402	                    end loop;
403	
404	                end loop;
405	
406	            end if;
407	
408	        end loop;
409	
410	        -- TB done
411	        test_runner_cleanup(runner);
412	    end process;
413	
414	end architecture;
