33	---------------------------------------------------------------------------------------------------
34	entity olo_base_ram_sdp is
35	    generic (
36	        Depth_g         : positive;
37	        Width_g         : positive;
38	        IsAsync_g       : boolean  := false;
39	        RdLatency_g     : positive := 1;
40	        RamStyle_g      : string   := "auto";
41	        RamBehavior_g   : string   := "RBW";
42	        UseByteEnable_g : boolean  := false;
43	        InitString_g    : string   := "";
44	        InitFormat_g    : string   := "NONE"
45	    );
46	    port (
47	        Clk         : in    std_logic;
48	        Rst         : in    std_logic                                  := '0';
49	        Wr_Addr     : in    std_logic_vector(log2ceil(Depth_g) - 1 downto 0);
50	        Wr_Ena      : in    std_logic                                  := '1';
51	        Wr_Be       : in    std_logic_vector(Width_g / 8 - 1 downto 0) := (others => '1');
52	        Wr_Data     : in    std_logic_vector(Width_g - 1 downto 0);
53	        Rd_Clk      : in    std_logic                                  := '0';
54	        Rd_Rst      : in    std_logic                                  := '0';
55	        Rd_Addr     : in    std_logic_vector(log2ceil(Depth_g) - 1 downto 0);
56	        Rd_Ena      : in    std_logic                                  := '1';
57	        Rd_Data     : out   std_logic_vector(Width_g - 1 downto 0);
58	        Rd_Valid    : out   std_logic
59	    );
60	end entity;
61	
62	---------------------------------------------------------------------------------------------------
63	-- Architecture
64	---------------------------------------------------------------------------------------------------
65	architecture rtl of olo_base_ram_sdp is
66	
67	    -- constants
68	    constant EntityName_c : string  := "olo_base_ram_sdp";
69	    constant BeCount_c    : integer := Width_g / 8;
70	
71	    -- Read Valid pipeline
72	    signal RdValidPipe : std_logic_vector(1 to RdLatency_g);
73	
74	    -- Synthesis attributes - Suppress shift register extraction
75	    attribute shreg_extract of RdValidPipe : signal is ShregExtract_SuppressExtraction_c;
76	
77	    -- components
